"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[6974],{24745:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Constructs a new `SlingshotController` for the given tool [Model] and [RoundCharacterController].","params":[{"name":"instance","desc":"","lua_type":"Model"},{"name":"roundCharController","desc":"","lua_type":"RoundCharacterController"}],"returns":[{"desc":"","lua_type":"SlingshotController"}],"function_type":"static","source":{"line":111,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}},{"name":"ActivatePrimary","desc":"Overrides [ToolController:ActivatePrimary] to fire a projectile.\\nIf `toActivate` is true, the slingshot will be drawn until the method is called again with `toActivate` set to false,\\nat which point the projectile will be fired.","params":[{"name":"toActivate","desc":"","lua_type":"boolean"}],"returns":[],"function_type":"method","tags":["Override"],"source":{"line":138,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}},{"name":"_init","desc":"Overrides [ToolController:_init] to generate the [SlingshotConfig] and create the `_onProjectileImpactEvent` [BindableEvent].","params":[],"returns":[],"function_type":"method","tags":["Override"],"private":true,"source":{"line":149,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}},{"name":"_fireProjectile","desc":"If `toFire` is true, the slingshot will be drawn, increasing the speed of the projectile,\\nuntil the method is called again with `toFire` set to false, at which point the projectile will be fired.","params":[{"name":"toFire","desc":"","lua_type":"boolean"}],"returns":[],"function_type":"method","private":true,"source":{"line":185,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}},{"name":"_onProjectileImpact","desc":"Handles the impact of a projectile on a [BasePart], registering the hit with the server as either a block or a character.","params":[{"name":"projectile","desc":"","lua_type":"ProjectileCaster.Projectile"},{"name":"raycastResult","desc":"","lua_type":"RaycastResult"}],"returns":[],"function_type":"method","private":true,"source":{"line":242,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}}],"properties":[{"name":"_config:","desc":"The [SlingshotConfig] generated from the [Configuration] found in the slingshot controller\'s `Instance`.","lua_type":"SlingshotConfig","private":true,"source":{"line":59,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}},{"name":"_toFire:","desc":"Whether the player is currently drawing the slingshot.","lua_type":"boolean","private":true,"source":{"line":65,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}},{"name":"_onProjectileImpactEvent:","desc":"A [BindableEvent] to be passed to the [ProjectileCaster] to handle projectile impacts.","lua_type":"BindableEvent","private":true,"source":{"line":71,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}}],"types":[],"name":"SlingshotController","desc":"SlingshotController extends [ToolController] to manage the behavior of a slingshot tool during gameplay. \\nIt allows players to fire projectiles using the [ProjectileCaster], handling the physics, visuals, and interactions \\nof the projectiles. The slingshot is equipped with a charging mechanic that determines projectile speed based on \\nhow long the player draws before firing.\\n\\n### Core Features:\\n- **Projectile Firing**: Allows players to fire projectiles with configurable speed, gravity, and lifetime.\\n- **Charging Mechanic**: Increases projectile speed dynamically based on the draw duration, up to a defined maximum.\\n- **Impact Handling**: Detects and processes projectile impacts on blocks or characters, registering hits with the server.\\n- **Real-Time Integration**: Uses Roblox\'s [RunService] to ensure smooth and consistent updates during gameplay.\\n\\n### Server Interaction:\\n- The `_fireProjectile` method fires the `FireProjectile` [RemoteEvent] to notify the server about the origin, direction, \\n  speed, and timestamp of the projectile being fired.\\n- The `_onProjectileImpact` method fires the `RegisterHit` [RemoteEvent] to notify the server of projectile impacts, \\n  specifying the [ProjectileHitType], the impacted part, and timing details.\\n- These remotes are handled by the [RoundPlayerHandler] on the server, which processes the projectile firing and \\n  hit registration to synchronize gameplay across clients and ensure consistent game state management.\\n\\n### Highlights:\\n- Implements the `ActivatePrimary` method to manage the slingshot\'s firing behavior.\\n- Uses [ProjectileCaster] for raycasting and managing projectile trajectories and collisions.","tags":["ToolController"],"source":{"line":99,"path":"src/Client/Classes/ToolController/SlingshotController.luau"}}')}}]);